content:
ey.as_str())
                .map_err(|e| CorviaError::Agent(format!("Failed to remove queue entry: {e}")))?;
        }
        write_txn.commit()
            .map_err(|e| CorviaError::Agent(format!("Failed to commit dequeue: {e}")))?;
